# -*- coding: utf-8 -*-
# 生成完整的 knowledge.js

out = open('knowledge.js', 'w', encoding='utf-8')
out.write('// 高中学习管理系统 - 知识点数据\n')
out.write('// 格式：knowledgeData[年级][学科] = [{知识点对象}, ...]\n')
out.write('window.knowledgeData = {\n')

# Helper to write a subject block
def write_subject(subject_name, items):
    out.write(f"        '{subject_name}': [\n")
    for it in items:
        content = it['content'].replace("'", "'")  # keep as-is, single quotes OK since no ' used inside content
        out.write(f"            {{ id: '{it['id']}', chapter: '{it['chapter']}', name: '{it['name']}', content: '{content}' }},\n")
    out.write('        ],\n')

# ========== 高一 ==========
out.write("    '高一': {\n")

# 高一 语文
write_subject('语文', [
    {'id':'yuwen-g1-1','chapter':'字音字形','name':'多音字辨析','content':'核心定义：一个字有两个或以上读音，不同读音表义不同、用法不同。<br>规则：1.根据词性定音，如"难"作形容词读nán，作名词读nàn。<br>2.根据词义定音，如"处"表"地方"读chù，表"对待"读chǔ。<br>3.根据口语/书面语定音，如"血"口语xiě，书面语xuè。<br>典型考点：给出词语选择正确读音；根据语境标注多音字读音。<br>易错点：混淆"薄"(báo/bó/bò)、"咽"(yān/yàn/yè)、"载"(zǎi/zài)的不同读音。'},
    {'id':'yuwen-g1-2','chapter':'字音字形','name':'形近字辨析','content':'核心定义：字形相近但读音、意义不同的字。<br>常见类型：1.笔画多少不同：己/已/巳；戊/戌/戍。<br>2.偏旁部首不同：噪/燥/躁；溢/缢/谥。<br>3.结构相似：葺/茸；徒/徙。<br>典型考点：找出错别字并改正；选择题判断有无错别字。<br>易错点："不胫而走"≠"不径而走"，"脍炙人口"≠"烩灸人口"，"墨守成规"≠"默守陈规"。'},
    {'id':'yuwen-g1-3','chapter':'词语运用','name':'成语辨析','content':'核心定义：成语是语言中经过长期使用、锤炼而形成的固定短语。<br>辨析角度：1.望文生义：如"差强人意"是大体令人满意，非不满意。<br>2.对象误用："豆蔻年华"仅指女子十三四岁。<br>3.褒贬不当："处心积虑"贬义，"殚精竭虑"褒义。<br>4.谦敬错位："抛砖引玉"是谦辞，不能用于对方。<br>典型考点：根据语境选填成语；判断成语使用正误。<br>易错点："无所不为"是贬义词，什么坏事都干；"首当其冲"是最先受到攻击。'},
    {'id':'yuwen-g1-4','chapter':'词语运用','name':'近义词辨析','content':'核心定义：意义相近但在词义、色彩、用法上有细微差别的词。<br>辨析方法：1.词义轻重不同：请求/恳求；轻视/鄙视。<br>2.范围大小不同：战争/战役/战斗；事情/事件/事故。<br>3.搭配对象不同："发扬"搭配优点、作风、传统；"发挥"搭配作用、威力、积极性。<br>4.感情色彩不同：果断(褒)/决断(中)/武断(贬)。<br>典型考点：根据语境选择恰当词语。<br>易错点："度过"用于时间，"渡过"用于江河或难关；"启用"用于物，"起用"用于人。'},
    {'id':'yuwen-g1-5','chapter':'病句辨析','name':'病句——搭配不当','content':'核心定义：句子成分之间或词语之间在意义上、语法上不能搭配。<br>类型：1.主谓搭配不当：他的学习态度明确了(态度应为"端正")。<br>2.动宾搭配不当：提高水平/能力/质量(正确)；提高效率(正确)。<br>3.主宾搭配不当：春天的北京是美丽的季节。<br>4.修饰语与中心语搭配不当：他有一双聪明的手。<br>5.一面与两面搭配不当：学习成绩的提高取决于学生自身是否努力。<br>典型考点：判断句子是否有语病；修改病句。<br>易错点："能否""是否""成败"等两面词需看前后是否对应。'},
    {'id':'yuwen-g1-6','chapter':'病句辨析','name':'病句——成分残缺或赘余','content':'核心定义：句子缺少必要成分或成分多余重复。<br>成分残缺：1.主语残缺：通过学习，使我明白了道理("通过"或"使"去掉一个)。<br>2.谓语残缺：我们正在努力为建设一个现代化的社会主义强国(缺谓语)。<br>3.宾语残缺：我们要尽一切力量使我国农业走上机械化(缺宾语"道路")。<br>成分赘余：1.语义重复：大约……左右；过分溺爱；免费赠送。<br>2.虚词多余：关于这个问题，我们已经研究过了("关于"可删)。<br>典型考点：判断语病类型并修改。<br>易错点："防止……不……"是双重否定错误；"避免……不要……"同理。'},
    {'id':'yuwen-g1-7','chapter':'文言文阅读','name':'文言实词——通假字与一词多义','content':'核心定义：通假字是用音同或音近字代替本字；一词多义指一个词有多个意义。<br>常见通假字："不亦说乎"的"说"通"悦"；"女知之乎"的"女"通"汝"。<br>一词多义推导方法：1.语境分析法；2.语法分析法(根据词性推断)。<br>3.联想推断法(联系成语或学过的词语)；4.结构对应法(对称结构中对应位置词义相近或相反)。<br>典型考点：解释加点词含义；选择题判断词义异同。<br>易错点："亡"有"逃跑/丢失/灭亡/通无"等义，需根据语境判断。'},
    {'id':'yuwen-g1-8','chapter':'文言文阅读','name':'文言虚词——高频虚词用法','content':'核心定义：文言虚词是不表示实在意义的词，包括代词、副词、介词、连词、助词等。<br>高频虚词：之、其、而、以、于、为、者、也、矣、乎、焉、何、乃、且、若、所、因、则。<br>"之"的用法：1.代词：代人/代物/代事；2.结构助词：的；3.主谓之间取消独立性；4.宾语前置标志；5.凑足音节。<br>"而"的用法：1.并列关系(而且)；2.承接关系(然后/就)；3.转折关系(但是/却)；4.修饰关系(地)。<br>典型考点：判断虚词意义和用法异同。<br>易错点："之"的主谓之间取消独立性用法容易被误判为"的"。'},
    {'id':'yuwen-g1-9','chapter':'文言文阅读','name':'文言句式——判断句、被动句、省略句','content':'核心定义：文言句式是文言文与现代汉语在句法上的差异。<br>判断句：1.……者，……也；2.……，……也；3.……者，……；4.……者也。<br>5.用"乃、则、即、皆、本、诚"等副词表判断。<br>被动句：1."于"字式：受制于人；2."见"字式：徒见欺；3."为"字式：为天下笑。<br>4."被"字式；5.无标志被动句：锲而不舍，金石可镂。<br>省略句：1.省主语；2.省谓语；3.省宾语(包括介词宾语)；4.省介词("于""以")。<br>典型考点：判断句式类型；翻译句子(注意补出省略成分)。<br>易错点：无标志被动句容易被误判为主动句。'},
    {'id':'yuwen-g1-10','chapter':'诗歌鉴赏','name':'诗歌意象与意境分析','content':'核心定义：意象是融入作者主观情感的客观物象；意境是意象组合形成的艺术境界。<br>常见意象含义：1.送别类：杨柳、长亭、酒、芳草。<br>2.思乡类：月亮、鸿雁、登高。<br>3.愁苦类：梧桐、芭蕉、猿啼、杜鹃、乌鸦、流水、细雨。<br>4.边塞类：大漠、黄沙、长城、胡马、羌笛。<br>意境类型：雄浑开阔、苍凉悲壮、闲适恬淡、清幽明净、沉郁孤愁。<br>典型考点：分析诗中意象含义；概括意境特点；分析情景关系。<br>答题范式：这首诗描绘了一幅……的画面，构成了……的意境，表达了作者……的感情。<br>易错点：意象含义需结合时代背景与作者风格综合判断。'},
    {'id':'yuwen-g1-11','chapter':'诗歌鉴赏','name':'诗歌表现手法','content':'核心定义：表现手法是作者在创作中为塑造形象、表达主旨所运用的具体手法。<br>常见手法：1.借景抒情/情景交融(最常见)；2.托物言志(咏物诗常用)。<br>3.对比与衬托(正衬/反衬，以乐景衬哀情是反衬)。<br>4.虚实结合(眼前之景为实，想象回忆之景为虚)。<br>5.动静结合(以静衬动/以动衬静)；6.用典；7.象征；8.比兴。<br>9.抑扬(欲扬先抑/欲抑先扬)；10.想象与联想。<br>典型考点：指出诗句运用的表现手法并分析其效果。<br>答题步骤：点手法+释手法(结合诗句)+析效果。<br>易错点：表现手法不等于修辞手法不等于表达方式。'},
    {'id':'yuwen-g1-12','chapter':'现代文阅读','name':'现代文内容理解与信息筛选','content':'核心定义：理解文章主要内容，筛选并整合文中信息。<br>信息筛选要点：1.通读全文，整体把握；2.明确题干要求，确定筛选范围。<br>3.找准对应语段，标出关键句；4.比对选项与原文，注意陷阱。<br>常见陷阱：1.以偏概全(部分代替整体)；2.混淆时态(未然/已然/或然/必然)。<br>3.张冠李戴(对象错位)；4.偷换概念；5.强加因果；6.无中生有。<br>典型考点：选择题(最常见)；简答题概括要点。<br>答题技巧：定位原文→比对差异→综合判断。<br>易错点：注意"可能""大概""也许"等修饰词不可随意替换。'},
    {'id':'yuwen-g1-13','chapter':'写作','name':'作文审题与立意','content':'核心定义：审题是准确理解题意；立意是确立文章中心思想。<br>审题方法：1.材料作文：抓关键词句；由果溯因；由物及人；联系实际。<br>2.命题作文：分析题目结构，抓核心词，注意修饰限制成分。<br>3.话题作文：围绕话题，化大为小，化虚为实。<br>立意要求：1.准确(符合题意)；2.鲜明(观点明确)；3.深刻(透过现象看本质)。<br>4.新颖(角度独特)；5.积极(思想健康)。<br>立意切入点：1.是什么；2.为什么；3.怎么办；4.会怎样。<br>典型考点：根据材料写作；根据题目写作。<br>易错点：偏离题意是最大失分点，务必紧扣材料核心。'},
    {'id':'yuwen-g1-14','chapter':'写作','name':'议论文结构与论证方法','content':'核心定义：议论文三要素为论点、论据、论证；结构是文章的组织框架。<br>基本结构：1.总分式(总分总/总分/分总)；2.并列式(分论点并列)。<br>3.递进式(是什么→为什么→怎么办)；4.对照式(正反对比)。<br>常见模式：五段三分式：开头点题→分论点1+论据+分析→分论点2+论据+分析→分论点3+论据+分析→结尾总结。<br>论证方法：1.举例论证；2.道理论证；3.对比论证；4.比喻论证；5.引用论证。<br>6.因果论证；7.假设论证。<br>论据类型：事实论据(事例、史实、统计数据)；道理论据(名言、谚语、公理)。<br>典型考点：议论文写作(核心考查文体)。<br>易错点：分论点不在一个平面上；有论据无论证分析。'},
    {'id':'yuwen-g1-15','chapter':'语言表达','name':'语言表达连贯与得体','content':'核心定义：连贯是指语句之间顺序合理、衔接紧密；得体是指语言符合特定语境。<br>连贯方法：1.话题一致(主语或陈述对象保持一致)；2.逻辑合理(时间/空间/逻辑顺序)。<br>3.句式协调(排比、对偶句结构一致)；4.前后照应(首尾呼应/前后呼应)。<br>得体原则：1.看对象(年龄、身份、文化层次)；2.看场合(正式/非正式)。<br>3.看目的(宣传/说服/邀请/感谢)；4.看文体(议论/说明/记叙/应用)。<br>谦辞：家(家父/家母/家兄)、舍(舍弟/舍妹)、小(小女/小店)、拙(拙见/拙作)。<br>敬辞：令(令尊/令堂/令郎)、贵(贵姓/贵庚)、高(高见/高寿)、大(大作/大驾)。<br>典型考点：排序题；补写句子；语言表达得体修改。<br>易错点：谦敬辞使用场合不清；排序忽略话题一致性。'}
])

out.write('    },\n')  # 高一结束
print('高一 written.')
out.close()

# Now write other parts - reopen in append mode
out = open('knowledge.js', 'a', encoding='utf-8')

# ========== 高二 ==========
out.write("    '高二': {\n")

write_subject_g2 = write_subject

# 高二 语文
write_subject_g2('语文', [
    {'id':'yuwen-g2-1','chapter':'散文阅读','name':'散文的特点与阅读方法','content':'核心定义：散文是一种自由灵活、抒写真实感受的文学体裁。<br>三大特点：形散神聚(选材广泛但中心明确)、意境深远(情景交融)、语言优美(凝练生动富有文采)。<br>分类：叙事散文、抒情散文、哲理散文、写景散文。<br>阅读方法：1.抓线索(物线/情线/事线/时空线)；2.抓关键词句(文眼、中心句、过渡句)；3.体会作者情感与思想；4.赏析语言特色与表现手法。<br>典型考点：概括主旨、分析线索、赏析句子、体会情感。<br>易错点：将散文等同于记叙文，忽略散文的抒情性与哲理性。'},
    {'id':'yuwen-g2-2','chapter':'散文阅读','name':'散文形象与意境分析','content':'核心定义：散文形象包括人物形象、景物形象、事物形象；意境是情与景的融合。<br>分析方法：1.人物形象：关注外貌、语言、动作、心理、神态描写及侧面烘托。<br>2.景物形象：分析意象特征、营造氛围、烘托情感、象征意义。<br>3.事物形象：分析物象的外在特征、内在品格、象征意义。<br>意境分析：描绘图景+概括特点(雄浑/壮阔/清幽/恬静/苍凉/凄清)+分析情感。<br>表现手法：借景抒情、托物言志、情景交融、以小见大、虚实结合、动静结合。<br>典型考点：分析形象特征；概括意境特点；分析形象的作用与意义。<br>易错点：形象分析流于表面，未深入挖掘其象征意义与情感内涵。'},
    {'id':'yuwen-g2-3','chapter':'小说阅读','name':'小说三要素与情节分析','content':'核心定义：小说是以刻画人物为中心，通过完整的故事情节和环境描写反映社会生活的文学体裁。<br>三要素：人物、情节、环境。<br>情节结构：开端(介绍背景引出人物)、发展(矛盾展开)、高潮(冲突最激烈处)、结局(矛盾解决)。<br>情节分析角度：1.线索设置(单线/双线/明线/暗线)；2.情节安排的技巧(悬念、伏笔、照应、铺垫、突转、巧合)；3.情节作用(推动情节、塑造人物、揭示主题、制造波澜)。<br>叙述视角：第一人称(真实亲切有限视角)、第三人称(全知全能灵活自由)、第二人称(直接对话亲切感)。<br>典型考点：概括故事情节；分析情节特点与作用；分析叙述技巧。<br>易错点：只复述情节不分析作用，忽略情节之间的因果联系。'},
    {'id':'yuwen-g2-4','chapter':'小说阅读','name':'人物形象与环境描写','content':'核心定义：人物形象是小说的核心，环境是人物活动的舞台。<br>人物塑造方法：1.正面描写：外貌、语言、动作、心理、神态、细节描写。<br>2.侧面描写：环境烘托、他人衬托、物象象征、对比反衬。<br>人物形象概括：身份地位+性格特征+精神品质+作者情感(喜爱/批判/同情)。<br>环境描写分类：自然环境(景物、气候、时节、地点)、社会环境(时代背景、社会风俗、人际关系)。<br>环境描写作用：1.交代时间地点、时代背景；2.渲染气氛营造氛围；3.烘托人物心情、衬托人物形象；4.推动情节发展；5.暗示/揭示主题；6.象征暗示。<br>典型考点：概括并分析人物形象；分析环境描写的特点与作用；分析塑造人物的手法。<br>易错点：人物形象分析不全面，忽略次要人物对主要人物的衬托作用。'},
    {'id':'yuwen-g2-5','chapter':'语言运用','name':'扩展语句与压缩语段','content':'核心定义：扩展语句是将简单句子按要求扩展为具体生动的长句或语段；压缩语段是提炼语段核心信息。<br>扩展语句类型：1.丰富句意式(添加修饰语、修辞)；2.补充续写式(根据语境补写)；3.情景演绎式(根据情境展开)；4.图表转化式。<br>扩展方法：1.添加修饰成分(定语、状语、补语)；2.运用修辞手法(比喻、拟人、排比)；3.运用表现手法(描写、抒情、议论)；4.拆分角度(视觉/听觉/嗅觉/味觉/触觉)。<br>压缩语段类型：1.新闻类(抓导语五W+H)；2.说明类(抓说明对象与特征)；3.议论类(抓论点论据)；4.描述类(抓描写对象与特征)。<br>压缩方法：1.摘取法(提取关键词句)；2.分层法(分层概括合并)；3.复取法(要素合并)。<br>典型考点：按要求扩展句子；概括新闻标题/一句话新闻；提取关键词。<br>易错点：扩展偏离中心或不够具体；压缩遗漏关键信息或改变原意。'},
    {'id':'yuwen-g2-6','chapter':'语言运用','name':'句式变换与仿用','content':'核心定义：句式变换是改变句子形式但不改变原意；仿用句式是仿照给定句式造句。<br>常见变换：1.长句与短句互变(长句拆短句、短句合并长句)；2.主动句与被动句互换；3.陈述句与反问句互换；4.整句与散句互变；5.常式句与变式句(倒装)；6.重组句子。<br>仿句类型：1.嵌入式(补全内容)；2.续写式(根据前文续写)；3.命题式(给定话题仿写)；4.开放式(自由发挥)。<br>仿写要求：1.句式一致(结构、修辞、语气)；2.话题一致(围绕中心)；3.修辞一致(比喻、拟人、排比等)；4.格调一致(感情色彩、语体风格)。<br>注意事项：1.仿句要从形似到神似；2.注意字数限制与评分标准；3.内容要有新意不可机械模仿。<br>典型考点：长短句互换；按要求仿写句子；整散句变换。<br>易错点：仿写忽视修辞要求或内容与原句风格不协调；变换句式时遗漏信息。'},
    {'id':'yuwen-g2-7','chapter':'古诗文默写','name':'古诗词默写与理解','content':'核心定义：准确记忆并理解古诗词文名句，能根据语境填写。<br>考查形式：1.直接默写(给出上句写下句或反之)；2.理解性默写(根据情境提示写出)；3.情境式默写(设置具体情境)。<br>备考策略：1.熟读背诵课本规定篇目；2.准确理解名句含义与出处；3.注意易错字(同音字、形似字、通假字)；4.分类整理(按主题/情感/作者/朝代)；5.反复默写巩固记忆。<br>常见主题名句分类：爱国忧民、思乡怀人、建功立业、离愁别绪、山水田园、咏史怀古、哲理感悟。<br>易错字提醒："唯/惟"、"长/常"、"青/清"、"生/身"、"暗/岸"、"悠/幽"等需根据原文仔细区分。<br>典型考点：课本规定篇目的名句默写。<br>易错点：背熟但写错字，或理解不清导致情境默写答非所问。'}
])

